```latex
\begin{figure}[htbp]
\centering
\begin{tikzpicture}[
    node distance=1.5cm and 2cm,
    boxstyle/.style={rectangle, draw, rounded corners, minimum width=2.8cm, minimum height=1cm, text centered, font=\small, fill=blue!10},
    appstyle/.style={rectangle, draw, rounded corners, minimum width=2.5cm, minimum height=0.8cm, text centered, font=\footnotesize, fill=orange!20},
    arrowstyle/.style={->, >=stealth, thick, color=blue!60}
]

% 中心节点 - 统一生成理解模型
\node[rectangle, draw, rounded corners, minimum width=4cm, minimum height=1.5cm, 
      text centered, font=\bfseries, fill=green!20, line width=1.5pt] (ufm) {统一生成理解模型\\(UFMs)};

% 核心能力
\node[boxstyle, above=0.8cm of ufm] (understand) {多模态理解};
\node[boxstyle, below=0.8cm of ufm] (generate) {多模态生成};
\node[boxstyle, left=1.5cm of ufm] (reasoning) {推理与预测};
\node[boxstyle, right=1.5cm of ufm] (planning) {决策与规划};

% 应用场景 - 上方
\node[appstyle, above left=1.8cm and 3cm of ufm] (robot) {机器人\\VLA策略};
\node[appstyle, above=2.5cm of ufm] (driving) {自动驾驶\\端到端规划};
\node[appstyle, above right=1.8cm and 3cm of ufm] (world) {世界模型\\4D预测};

% 应用场景 - 下方
\node[appstyle, below left=1.8cm and 3cm of ufm] (medical) {医学影像\\诊断与生成};
\node[appstyle, below=2.5cm of ufm] (vision2d) {2D视觉任务\\检测/分割};
\node[appstyle, below right=1.8cm and 3cm of ufm] (vision3d) {3D视觉任务\\重建/生成};

% 连接线 - 核心能力
\draw[arrowstyle, <->] (understand) -- (ufm);
\draw[arrowstyle, <->] (generate) -- (ufm);
\draw[arrowstyle, <->] (reasoning) -- (ufm);
\draw[arrowstyle, <->] (planning) -- (ufm);

% 连接线 - 应用场景
\draw[arrowstyle, color=red!60] (ufm) -- (robot);
\draw[arrowstyle, color=red!60] (ufm) -- (driving);
\draw[arrowstyle, color=red!60] (ufm) -- (world);
\draw[arrowstyle, color=red!60] (ufm) -- (medical);
\draw[arrowstyle, color=red!60] (ufm) -- (vision2d);
\draw[arrowstyle, color=red!60] (ufm) -- (vision3d);

% 应用特点标注
\node[font=\tiny, text width=2cm, align=center, below=0.05cm of robot] 
      {动作预测\\推理与规划};
\node[font=\tiny, text width=2cm, align=center, below=0.05cm of driving] 
      {场景生成\\轨迹规划};
\node[font=\tiny, text width=2cm, align=center, below=0.05cm of world] 
      {物理约束\\时空一致};
\node[font=\tiny, text width=2cm, align=center, above=0.05cm of medical] 
      {报告生成\\影像合成};
\node[font=\tiny, text width=2cm, align=center, above=0.05cm of vision2d] 
      {感知理解\\标签生成};
\node[font=\tiny, text width=2cm, align=center, above=0.05cm of vision3d] 
      {几何建模\\点云重建};

% 添加图例
\node[rectangle, draw, rounded corners, text width=8cm, align=left, font=\tiny,
      below=3.5cm of ufm] (legend) {
    \textbf{关键特性:}\\
    • 统一框架：文本、图像、视频、动作多模态处理\\
    • 端到端：从感知到决策的闭环\\
    • 可扩展：大规模数据驱动的泛化能力\\
    • 物理约束：符合真实世界动态规律
};

\end{tikzpicture}
\caption{统一生成理解模型的主要应用场景}
\label{fig:ufm_applications}
\end{figure}
```

